import React from "react";
import { useNavigate } from "react-router-dom";
import Navbar from "../components/Navbar";
import "../App.css";

function Landing() {
  const navigate = useNavigate();

  const handleRoleSelect = (role) => {
    // 🔐 Role store for login/signup flow
    localStorage.setItem("role", role);
    navigate("/login");
  };

  return (
    <>
      {/* 🌐 Public Navbar */}
      <Navbar variant="public" />

      {/* 🌟 HERO SECTION */}
      <div className="hero-landing">

        {/* 🔥 Brand / Website Name */}
        <h1 className="hero-title">
          🧿 <span style={{ fontWeight: 600 }}>RetailVision AI</span>
        </h1>

        {/* 🧠 Tagline / Slogan */}
        <p className="hero-subtitle">
          Smarter inventory. Clearer decisions.
        </p>

        {/* 🎯 Short description */}
        <p
          style={{
            color: "var(--text-muted)",
            maxWidth: "620px",
            marginTop: "18px",
            fontSize: "16px",
          }}
        >
          Predict demand, optimize stock, and execute retail strategy
          with AI-powered insights.
        </p>

        {/* 🔐 Role-based CTA */}
        <div className="hero-actions">
          <button onClick={() => handleRoleSelect("admin")}>
            Continue as Admin
          </button>

          <button onClick={() => handleRoleSelect("staff")}>
            Continue as Staff
          </button>
        </div>

      </div>
    </>
  );
}

export default Landing;
